-- ============================================================
-- B5 . Drop de documentos_tipos_reglas (tabla huerfana, 680 filas)
-- ------------------------------------------------------------
-- Esta tabla quedo huerfana: las funciones que la leian/escribian se
-- eliminaron el 2026-06-17 (ver tombstone en lib/actions/catalogacion.ts).
-- La aplicabilidad de documentos hoy vive en la matriz nueva
-- documentos_tipos_tipos_establecimiento (+ documentos_tipos_actividades para
-- CIIU) que consume getLegajoEsperados. NINGUN codigo vivo usa esta tabla.
--
-- ANTES de dropear, se deja un BACKUP de las 680 filas como INSERTs idempotentes
-- (snapshot 2026-06-24, via Management API). Para revertir: recrear la tabla
-- desde 20260523000002_unify_documentos_tipos_reglas.sql y correr el INSERT de
-- abajo. El bloque esta envuelto en un DO para no fallar si la tabla ya no existe.
-- ============================================================

-- -- Backup de las 680 filas (idempotente) ----------------------
DO $backup$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = '''public''' AND table_name = '''documentos_tipos_reglas'''
  ) THEN
    ON CONFLICT (id) DO NOTHING;
  END IF;
END
$backup$;

-- -- DROP definitivo --------------------------------------------
-- No hay FKs entrantes (verificado 2026-06-24) -> sin CASCADE.
DROP TABLE IF EXISTS public.documentos_tipos_reglas;
